class CircularBufferMulti[T <: Data](t: T, n: Int, capacity: Int) extends Module {
  // For the time being, restrict to powers of 2
  assert(isPow2(n))
  assert(isPow2(capacity))
  val io = IO(new Bundle {
    val enqValid = Input(UInt(log2Ceil(n + 1).W))
    val enqData = Input(Vec(n, t))

    val nEnqueued = Output(UInt(log2Ceil(capacity + 1).W))
    val nSpace = Output(UInt(log2Ceil(capacity + 1).W))

    val dataOut = Output(Vec(n, t))
    val deqReady = Input(UInt(log2Ceil(n + 1).W))

    val flush = Input(Bool())
  })
  dontTouch(io)

  // Note first assert below should be sufficient it allows enqueueing items when buffer
  // is full or close to full provided deqReady >= enqValid.
  // The second assert is more conservative, and will never allow enqueueing more items
  // than there is space in the buffer, under any circumstances. May be removed if
  // desire for more is greater than the need to be more conservative.
  assert(io.nEnqueued +& io.enqValid -& io.deqReady <= capacity.U)
  assert(io.enqValid <= (capacity.U -& io.nEnqueued))

  assert(io.deqReady <= io.nEnqueued)

  val buffer = RegInit(VecInit.fill(capacity)(0.U.asTypeOf(t)))
  val enqPtr = RegInit(0.U(log2Ceil(capacity).W))
  val deqPtr = RegInit(0.U(log2Ceil(capacity).W))

  val expandedInput = Wire(Vec(capacity, Valid(t)))
  for (i <- 0 until capacity) {
    if (i < n) {
      expandedInput(i) := MakeValid(i.U < io.enqValid, io.enqData(i))
    } else {
      expandedInput(i) := MakeInvalid(t)
    }
  }

  val rotatedInput = RotateVectorLeft(expandedInput, enqPtr)
  for (i <- 0 until capacity) {
    buffer(i) := Mux(rotatedInput(i).valid, rotatedInput(i).bits, buffer(i))
  }

  var nEnqueued = RegInit(0.U(io.nEnqueued.getWidth.W))
  enqPtr    := Mux(io.flush, 0.U, enqPtr + io.enqValid)
  deqPtr    := Mux(io.flush, 0.U, deqPtr + io.deqReady)
  nEnqueued := Mux(io.flush, 0.U, nEnqueued + io.enqValid - io.deqReady)

  io.nEnqueued := nEnqueued
  io.nSpace := capacity.U - nEnqueued

  val outputBufferView = RotateVectorRight(buffer, deqPtr)
  for (i <- 0 until n) {
    io.dataOut(i) := outputBufferView(i)
  }
}

  val dtcmSizeKBytesHighmem = 1024
  def apply(): Parameters = {
    return new Parameters()
  }
  def apply(m: Seq[MemoryRegion]): Parameters = {
    return new Parameters(m)
  }
}

class Parameters(var m: Seq[MemoryRegion] = Seq(), val hartId: Int = 0, val xlen: Int = 32) {
  // Machine.
  val programCounterBits = xlen
  val instructionBits = 32
  val instructionLanes = 4

  // Enable extra logic for verification purposes.
  var enableVerification = false

  // TODO: It might seem intuitive to couple exposeDebugPorts and
  // enableVerification, as debug ports are only needed for verification.
  // However, coupling them is not trivial because enableVerification also
  // enables the full Retirement Buffer (ROB) tracking mode (mini = false).
  // Under configurations with RVV disabled but Float enabled (like core_mini_axi_sim),
  // the full ROB mode has hardware bugs/hangs (e.g. vector store waits and reset
  // oscillations). We still need the debug ports exposed for these targets to
  // generate instruction traces for riscv-dv co-simulation, but we must run
  // the ROB in mini mode (enableVerification = false) to avoid the hangs.
  // Thus, we keep these parameters decoupled.
  // Expose the debug/trace ports at the module boundary.
  var exposeDebugPorts = false

  // Expose ports if explicitly requested, or automatically if full verification is enabled.
  def shouldExposeDebugPorts: Boolean = { exposeDebugPorts || enableVerification }

  // Enable RVV. This conforms to the RVV1.0 specification.
  var enableRvv = false
  val rvvVlen = 128
  def rvvVlenb: Int = { rvvVlen / 8 }

  def useRetirementBuffer: Boolean = { enableVerification }

  // Scalar Floating point
  var enableFloat = false
  var enableZfbfmin = false
  var enableVectorBf16 = false
  // Use the Div/Sqrt module from PULP instead of E906.
  // It is smaller, but has small rounding errors.
  val floatPulpDivsqrt = 0

  val scalarRegCount = 32
  val scalarRegCountWidth = log2Ceil(scalarRegCount)
  val floatRegCount = 32
  val floatRegfileBaseAddr = 32
  val floatRegCountWidth = log2Ceil(floatRegCount)
  val rvvRegfileBaseAddr = 64
  val rvvRegCount = 32
  val rvvRegCountWidth = log2Ceil(rvvRegCount)
  val retirementBufferSize = 8
  def retirementBufferIdxWidth: Int = {
    val activeFloatRegCount = (if (enableFloat) { floatRegCount } else { 0 })
    // +2 is for the "no write" and "store" dummy registers.
    log2Ceil(scalarRegCount + activeFloatRegCount + rvvRegCount + 2)
  }

  // L0ICache Fetch unit.
  var enableFetchL0 = true
  val fetchCacheBytes = 1024

  // Scalar Core Fetch bus.
  val fetchAddrBits = programCounterBits   // do not change
  var fetchDataBits = 256  // do not change
  def fetchInstrSlots: Int = {
    assert(fetchDataBits % 32 == 0)
    assert(instructionBits % 32 == 0)
    assert(fetchDataBits % instructionBits == 0)
    fetchDataBits / instructionBits
  }

  // Scalar Core Load Store Unit bus.
  val lsuAddrBits = programCounterBits  // do not change
  var lsuDataBits = 256
  def lsuDataBytes: Int = { lsuDataBits / 8 }
  val lsuDelayPipelineLen = 1
  def dbusSize: Int = { log2Ceil(lsuDataBits / 8) + 1 }

  // TCM Size Configuration
  var itcmSizeKBytes = Parameters.itcmSizeKBytesDefault
  var dtcmSizeKBytes = Parameters.dtcmSizeKBytesDefault

  // [Internal] L1ICache interface.
  val l1islots = 256
  val l1iassoc = 4
  val axi0IdBits = 4  // (1x banks, 4 bits unused)
  val axi0AddrBits = 32
  def axi0DataBits: Int = { fetchDataBits }

  // [Internal] L1DCache interface.
  val l1dslots = 256  // (x2 banks)
  val l1dassoc = 4
  val axi1IdBits = 4  // (x2 banks, 3 bits unused)

class IBusIO(p: Parameters) extends Bundle {
  // Control Phase.
  val valid = Output(Bool())
  val ready = Input(Bool())
  val addr = Output(UInt(p.fetchAddrBits.W))
  // Read Phase.
  val rdata = Input(UInt(p.fetchDataBits.W))
  // Fault information.
  val fault = Input(Valid(new FaultInfo(p)))

  def fire: Bool = valid && ready
}

class FetchInstruction(p: Parameters) extends Bundle {
  val addr = UInt(p.programCounterBits.W)
  val inst = UInt(p.instructionBits.W)
  val brchFwd = Bool()
}

class FetchIO(p: Parameters) extends Bundle {
  val lanes = Vec(p.instructionLanes, Decoupled(new FetchInstruction(p)))
}

abstract class FetchUnit(p: Parameters) extends Module {
  val io = IO(new Bundle {
    val csr = new CsrInIO(p)
    val debug_pc = Flipped(Valid(UInt(p.fetchAddrBits.W)))
    val ibus = new IBusIO(p)
    val inst = new FetchIO(p)
    val branch = Flipped(Vec(p.instructionLanes, new BranchTakenIO(p)))
